// And groups predicates with the AND operator between them.
func And(predicates ...predicate.ProductionFact) predicate.ProductionFact {
	return predicate.ProductionFact(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.ProductionFact) predicate.ProductionFact {
	return predicate.ProductionFact(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.ProductionFact) predicate.ProductionFact {
	return predicate.ProductionFact(sql.NotPredicates(p))
}
